# ── Colours ───────────────────────────────────────────────────────────────────

class C:
    _t     = sys.stdout.isatty()
    BOLD   = "\033[1m"  if _t else ""
    CYAN   = "\033[36m" if _t else ""
    GREEN  = "\033[32m" if _t else ""
    YELLOW = "\033[33m" if _t else ""
    RED    = "\033[31m" if _t else ""
    RESET  = "\033[0m"  if _t else ""

def info(m):  print(f"{C.CYAN}[INFO ] {C.RESET}{m}")
def ok(m):    print(f"{C.GREEN}[OK   ] {C.RESET}{m}")
def warn(m):  print(f"{C.YELLOW}[WARN ] {C.RESET}{m}")
def error(m): print(f"{C.RED}[ERROR] {C.RESET}{m}", file=sys.stderr)
def head(m):  print(f"\n{C.BOLD}{C.CYAN}{m}{C.RESET}")


# ── D-Bus receiver ────────────────────────────────────────────────────────────

RECEIVER_XML = f"""
<node>
  <interface name='{RECEIVER_IFACE}'>
    <method name='receiveResult'>
      <arg type='s' name='test_name' direction='in'/>
      <arg type='s' name='json_data' direction='in'/>
    </method>
  </interface>
</node>
"""


class MutationTestReceiver:
    dbus = RECEIVER_XML

    def __init__(self) -> None:
        self._results: dict[str, object] = {}
        self._events:  dict[str, threading.Event] = {}
        self._lock = threading.Lock()

    def expect(self, test_name: str) -> threading.Event:
        """Register an event to wait on for a named test result."""
        ev = threading.Event()
        with self._lock:
            self._events[test_name] = ev
        return ev

    def receiveResult(self, test_name: str, json_data: str) -> None:
        try:
            data = json.loads(json_data)
        except Exception as exc:
            data = {"parseError": str(exc), "raw": json_data[:200]}

        with self._lock:
            self._results[test_name] = data
            ev = self._events.get(test_name)
        if ev:
            ev.set()

    def get(self, test_name: str) -> object:
        with self._lock:
            return self._results.get(test_name)


# ── Script runner ─────────────────────────────────────────────────────────────

class ScriptRunner:
    """Loads a KWin JS snippet, runs it, waits for result, unloads."""

    def __init__(self, scripting, receiver: MutationTestReceiver) -> None:
        self.scripting = scripting
        self.receiver  = receiver

    def run(self, test_name: str, js_body: str, timeout: float = 5.0) -> object:
        """
        Wrap *js_body* in boilerplate, load as a KWin script, wait for the
        receiveResult() callback, unload, and return the parsed result dict.
        """
        svc   = RECEIVER_SERVICE
        path  = RECEIVER_PATH
        iface = RECEIVER_IFACE
        name  = test_name

        js = f"""
// KWin mutation test — {name}
var _svc   = "{svc}";
var _path  = "{path}";
var _iface = "{iface}";
var _name  = "{name}";

function send(data) {{
    callDBus(_svc, _path, _iface, "receiveResult", _name,
             JSON.stringify(data));
}}

try {{
    {js_body}
}} catch(e) {{
    send({{ fatalError: String(e) }});
}}
"""
        js_fd, js_path = tempfile.mkstemp(suffix=".js", prefix=f"kwin_mut_{name}_")
        os.close(js_fd)
        script_id = None
        ev = self.receiver.expect(test_name)

        try:
            with open(js_path, "w") as f:
                f.write(js)
            script_id = self.scripting.loadScript(js_path)
            self.scripting.start()
        except Exception as exc:
            os.unlink(js_path)
            return {"loadError": str(exc)}

        ev.wait(timeout=timeout)

        try:
            if script_id is not None:
                self.scripting.unloadScript(str(script_id))
        except Exception:
            pass
        try:
            os.unlink(js_path)
        except OSError:
            pass

        result = self.receiver.get(test_name)
        if result is None:
            return {"timeout": True, "test": test_name}
        return result


# ── Individual tests ──────────────────────────────────────────────────────────

def test_virtual_desktops(runner: ScriptRunner, bus) -> list[dict]:
    """
    Test A — enumerate virtual desktops two ways:
      1. workspace.desktops  (KWin scripting API)
      2. /VirtualDesktopManager desktops D-Bus property
    """
    head("Test A — Virtual desktop enumeration")

    # Via KWin scripting
    result = runner.run("virtual_desktops", """
var desks = [];
try {
    var ds = workspace.desktops;
    for (var i = 0; i < ds.length; i++) {
        var d = ds[i];
        desks.push({
            id:     String(d.id   || d.x11DesktopNumber || i+1),
            name:   String(d.name || ""),
            number: Number(d.x11DesktopNumber || i+1),
        });
    }
    send({ source: "workspace.desktops", desktops: desks, count: ds.length });
} catch(e) {
    // Older API: workspace.currentDesktop is an int, no .desktops array
    send({ source: "fallback", error: String(e),
           currentDesktop: Number(workspace.currentDesktop || 0) });
}
""")
    info(f"workspace.desktops result:")
    _print_result(result)

    # Via VirtualDesktopManager D-Bus property (always works)
    try:
        vdm       = bus.get(KWIN_SERVICE, VDM_PATH)
        vdm_desks = vdm.desktops          # a(iss): (number, id, name)
        current   = vdm.current           # string UUID of current desktop
        count     = vdm.count
        info(f"VirtualDesktopManager: {count} desktop(s), current='{current}'")
        parsed = []
        for item in vdm_desks:
            # item is a tuple/struct: (x11_number, uuid_id, name)
            parsed.append({
                "x11Number": int(item[0]),
                "id":        str(item[1]),
                "name":      str(item[2]),
            })
            info(f"  desktop {item[0]}: id='{item[1]}'  name='{item[2]}'")
        return parsed
    except Exception as exc:
        warn(f"VirtualDesktopManager query failed: {exc}")
        return []


def test_screen_enumeration(runner: ScriptRunner) -> list[dict]:
    """
    Test B — enumerate screens/outputs via workspace scripting API.
    We try several property names since this changed across Plasma versions.
    """
    head("Test B — Screen / output enumeration")

    result = runner.run("screens", """
var info = {};

// Try workspace.screens (Plasma 6 API)
try {
    var screens = workspace.screens;
    var arr = [];
    for (var i = 0; i < screens.length; i++) {
        var s = screens[i];
        arr.push({
            name:         String(s.name         || ""),
            manufacturer: String(s.manufacturer || ""),
            model:        String(s.model        || ""),
            geometry: {
                x:      Number(s.geometry ? s.geometry.x      : 0),
                y:      Number(s.geometry ? s.geometry.y      : 0),
                width:  Number(s.geometry ? s.geometry.width  : 0),
                height: Number(s.geometry ? s.geometry.height : 0),
            },
            devicePixelRatio: Number(s.devicePixelRatio || 1),
        });
    }
    info.screens      = arr;
    info.screenCount  = screens.length;
    info.screensAPI   = "workspace.screens";
} catch(e) {
    info.screensError = String(e);
}

// Also try workspace.numScreens + workspace.clientArea (older API)
try {
    info.numScreens = Number(workspace.numScreens || 0);
} catch(e) {
    info.numScreens = -1;
}

// Active screen name
try {
    info.activeScreen = String(workspace.activeScreen.name || "");
} catch(e) {
    try {
        info.activeScreen = String(workspace.activeScreen || "");
    } catch(e2) {
        info.activeScreenError = String(e2);
    }
}

send(info);
""")

    if "fatalError" in result:
        error(f"Screen test fatal error: {result['fatalError']}")
        return []

    screens = result.get("screens", [])
    info(f"Screen API     : {result.get('screensAPI', 'unknown')}")
    info(f"Screen count   : {result.get('screenCount', '?')}")
    info(f"numScreens     : {result.get('numScreens', '?')}")
    info(f"Active screen  : {result.get('activeScreen', '?')}")
    print()

    for i, s in enumerate(screens):
        g = s.get("geometry", {})
        print(f"  Screen {i}: {s.get('name','?')!r}")
        print(f"    geometry : {g.get('x')},{g.get('y')}  "
              f"{g.get('width')}x{g.get('height')}")
        print(f"    model    : {s.get('manufacturer','')} {s.get('model','')}")
        print(f"    dpr      : {s.get('devicePixelRatio', 1)}")

    return screens


def test_find_window_by_id(runner: ScriptRunner, target_id: str) -> dict:
    """
    Test C — find a window by internalId via workspace.windowList().
    This confirms the lookup pattern the library will use.
    """
    head(f"Test C — Find window by internalId")
    info(f"Target: {target_id}")

    # Normalise: strip braces for comparison since KWin may include them
    bare_id = target_id.strip("{}")

    result = runner.run("find_window", f"""
var targetId = "{bare_id}";
var windows  = workspace.windowList();
var found    = null;

for (var i = 0; i < windows.length; i++) {{
    var w   = windows[i];
    var wid = String(w.internalId || "").replace(/[{{}}]/g, "");
    if (wid === targetId) {{
        found = {{
            internalId:      String(w.internalId),
            resourceClass:   String(w.resourceClass   || ""),
            caption:         String(w.caption         || ""),
            pid:             Number(w.pid             || 0),
            x:               Number(w.x               || 0),
            y:               Number(w.y               || 0),
            width:           Number(w.width           || 0),
            height:          Number(w.height          || 0),
            minimized:       Boolean(w.minimized),
            maximized:       Boolean(w.maximized),
            desktop:         String(w.desktops && w.desktops[0]
                                    ? w.desktops[0].id : ""),
        }};
        break;
    }}
}}

if (found) {{
    send({{ status: "found", window: found, searchedCount: windows.length }});
}} else {{
    send({{ status: "not_found", searchedCount: windows.length,
            targetId: targetId }});
}}
""")

    if result.get("status") == "found":
        w = result["window"]
        ok(f"Window found (searched {result.get('searchedCount','?')} windows)")
        info(f"  resourceClass : {w.get('resourceClass')!r}")
        info(f"  caption       : {w.get('caption')!r}")
        info(f"  geometry      : {w.get('x')},{w.get('y')}  "
             f"{w.get('width')}x{w.get('height')}")
        info(f"  desktop id    : {w.get('desktop')!r}")
        info(f"  minimized     : {w.get('minimized')}")
        info(f"  maximized     : {w.get('maximized')}")
    else:
        warn(f"Window NOT found — searched {result.get('searchedCount','?')} windows")
        warn(f"  The internalId may have changed since the window was identified")

    return result


def test_window_desktop_property(runner: ScriptRunner, target_id: str) -> None:
    """
    Test D — inspect how desktops/screens are represented on a window object.
    This tells us the exact API to use for move-to-desktop and move-to-screen.
    """
    head("Test D — Window desktop/screen property inspection")

    bare_id = target_id.strip("{}")

    result = runner.run("window_placement", f"""
var targetId = "{bare_id}";
var windows  = workspace.windowList();
var info     = {{ found: false }};

for (var i = 0; i < windows.length; i++) {{
    var w   = windows[i];
    var wid = String(w.internalId || "").replace(/[{{}}]/g, "");
    if (wid !== targetId) continue;

    info.found = true;

    // Desktop-related properties
    try {{ info.onAllDesktops = Boolean(w.onAllDesktops); }} catch(e) {{}}

    // w.desktops — array of desktop objects (Plasma 6)
    try {{
        var ds = w.desktops;
        info.desktopsType  = typeof ds;
        info.desktopsLen   = ds ? ds.length : -1;
        if (ds && ds.length > 0) {{
            info.desktop0Id     = String(ds[0].id     || "");
            info.desktop0Name   = String(ds[0].name   || "");
            info.desktop0Number = Number(ds[0].x11DesktopNumber || 0);
        }}
    }} catch(e) {{ info.desktopsError = String(e); }}

    // w.output / w.screen — screen assignment (Plasma 6 vs older)
    try {{
        var out = w.output;
        info.outputName  = String(out ? (out.name || out) : "");
        info.outputType  = typeof out;
    }} catch(e) {{ info.outputError = String(e); }}

    // sendToOutput method availability
    try {{
        info.hasSendToOutput = (typeof w.sendToOutput === "function");
    }} catch(e) {{ info.hasSendToOutput = false; }}

    // setMaximize method
    try {{
        info.hasSetMaximize = (typeof w.setMaximize === "function");
    }} catch(e) {{ info.hasSetMaximize = false; }}

    // frameGeometry (preferred over x/y/width/height for setting)
    try {{
        var fg = w.frameGeometry;
        info.frameGeometry = {{
            x: Number(fg.x), y: Number(fg.y),
            width: Number(fg.width), height: Number(fg.height)
        }};
        info.hasFrameGeometrySetter = true;  // we'll test mutation separately
    }} catch(e) {{ info.frameGeometryError = String(e); }}

    break;
}}

send(info);
""")

    if not result.get("found"):
        warn("Window not found for property inspection")
        return

    ok("Window placement properties:")
    for key in (
        "onAllDesktops",
        "desktopsType", "desktopsLen",
        "desktop0Id", "desktop0Name", "desktop0Number",
        "desktopsError",
        "outputName", "outputType", "outputError",
        "hasSendToOutput", "hasSetMaximize",
        "frameGeometry", "frameGeometryError",
    ):
        if key in result:
            print(f"  {key:<30} {result[key]!r}")


def test_mutations(runner: ScriptRunner, target_id: str, desktops: list[dict]) -> None:
    """
    Test E — MUTATING tests (only run with --mutate flag).
    Performs a sequence of operations and restores original state afterwards.

    Operations tested:
      1. Unmaximize (if maximized)
      2. Resize to 800x600
      3. Move to a different position
      4. Maximize
      5. Restore original geometry
    """
    head("Test E — Mutation tests (--mutate)")
    warn("These tests WILL briefly move/resize the target window.")
    warn("Original geometry will be restored at the end.")
    print()

    bare_id = target_id.strip("{}")

    result = runner.run("mutate_geometry", f"""
var targetId = "{bare_id}";
var windows  = workspace.windowList();

for (var i = 0; i < windows.length; i++) {{
    var w   = windows[i];
    var wid = String(w.internalId || "").replace(/[{{}}]/g, "");
    if (wid !== targetId) continue;

    var orig = {{
        x:        Number(w.frameGeometry.x),
        y:        Number(w.frameGeometry.y),
        width:    Number(w.frameGeometry.width),
        height:   Number(w.frameGeometry.height),
        maximized: Boolean(w.maximized),
        minimized: Boolean(w.minimized),
    }};

    var steps = [];
    var errors = [];

    // Step 1: unmaximize if needed so we can resize
    try {{
        if (w.maximized) {{
            w.setMaximize(false, false);
            steps.push("unmaximized");
        }}
    }} catch(e) {{ errors.push("unmaximize: " + String(e)); }}

    // Step 2: resize to 800x600
    try {{
        w.frameGeometry = Qt.rect(orig.x, orig.y, 800, 600);
        steps.push("resized to 800x600");
    }} catch(e) {{ errors.push("resize: " + String(e)); }}

    // Brief pause (the script engine is synchronous so we use a loop)
    var t = Date.now(); while(Date.now() - t < 300) {{}}

    // Step 3: move 50px right and down
    try {{
        w.frameGeometry = Qt.rect(orig.x + 50, orig.y + 50, 800, 600);
        steps.push("moved +50,+50");
    }} catch(e) {{ errors.push("move: " + String(e)); }}

    var t2 = Date.now(); while(Date.now() - t2 < 300) {{}}

    // Step 4: maximize
    try {{
        w.setMaximize(true, true);
        steps.push("maximized");
    }} catch(e) {{ errors.push("maximize: " + String(e)); }}

    var t3 = Date.now(); while(Date.now() - t3 < 500) {{}}

    // Step 5: restore original state
    try {{
        w.setMaximize(false, false);
        w.frameGeometry = Qt.rect(orig.x, orig.y, orig.width, orig.height);
        if (orig.maximized) {{ w.setMaximize(true, true); }}
        steps.push("restored");
    }} catch(e) {{ errors.push("restore: " + String(e)); }}

    send({{
        status:  errors.length === 0 ? "ok" : "partial",
        steps:   steps,
        errors:  errors,
        original: orig,
    }});
    break;
}}
""", timeout=8.0)

    if result.get("timeout"):
        warn("Mutation test timed out")
        return

    status = result.get("status", "?")
    steps  = result.get("steps", [])
    errors = result.get("errors", [])

    if status == "ok":
        ok(f"All mutation steps succeeded:")
    else:
        warn(f"Partial success ({len(errors)} error(s)):")

    for s in steps:
        print(f"  ✓ {s}")
    for e in errors:
        print(f"  ✗ {e}")

    orig = result.get("original", {})
    info(f"Original geometry restored: "
         f"{orig.get('x')},{orig.get('y')}  "
         f"{orig.get('width')}x{orig.get('height')}")


# ── Helpers ───────────────────────────────────────────────────────────────────

def _print_result(result: object, indent: int = 2) -> None:
    pad = " " * indent
    if isinstance(result, dict):
        for k, v in result.items():
            if isinstance(v, (dict, list)):
                print(f"{pad}{k}:")
                _print_result(v, indent + 2)
            else:
                print(f"{pad}{k:<30} {v!r}")
    elif isinstance(result, list):
        for item in result:
            _print_result(item, indent)
    else:
        print(f"{pad}{result!r}")


def pick_target_window(bus) -> str | None:
    """
    If --id not given, use getWindowInfo via queryWindowInfo (interactive
    click-to-select) OR just pick the first non-plasmashell window from
    a quick snapshot.
    """
    info("No --id given — picking first non-plasmashell window from snapshot ...")
    try:
        kwin = bus.get(KWIN_SERVICE, "/KWin")
        # We can't call getWindowList, so we inject a quick snapshot script
        # using the same approach as the probe
        return None   # signal to use interactive selection below
    except Exception:
        return None


# ── Main ──────────────────────────────────────────────────────────────────────

def main() -> None:
    parser = argparse.ArgumentParser(
        prog="kwin_mutation_test.py",
        description="KWin window mutation and screen API verification tests.",
    )
    parser.add_argument(
        "--id", dest="window_id", default="", metavar="UUID",
        help="internalId of window to use for tests C/D/E (from kwin_window_probe.py)",
    )
    parser.add_argument(
        "--mutate", action="store_true",
        help="Also run Test E: actually move/resize the window (restores afterwards)",
    )
    args = parser.parse_args()

    head("═══ KWin Mutation & Screen API Test ═══════════════════════════")
    if args.window_id:
        info(f"Target window : {args.window_id}")
    else:
        info("Target window : (none — Tests C/D/E will be skipped)")
    info(f"Mutate        : {args.mutate}")

    bus      = SessionBus()
    receiver = MutationTestReceiver()

    # Publish receiver and start GLib loop
    try:
        registration = bus.publish(RECEIVER_SERVICE, (RECEIVER_PATH, receiver))
    except Exception as exc:
        error(f"Cannot publish receiver service: {exc}")
        error("Is another instance already running?")
        sys.exit(1)

    loop        = GLib.MainLoop()
    loop_thread = threading.Thread(target=loop.run, daemon=True)
    loop_thread.start()

    scripting = bus.get(KWIN_SERVICE, SCRIPTING_PATH)
    runner    = ScriptRunner(scripting, receiver)

    ok("Infrastructure ready — running tests\n")

    try:
        # Test A: Virtual desktops
        desktops = test_virtual_desktops(runner, bus)

        # Test B: Screen enumeration
        screens = test_screen_enumeration(runner)

        # Tests C / D / E require a target window
        if args.window_id:
            # Test C: Find window by ID
            find_result = test_find_window_by_id(runner, args.window_id)

            if find_result.get("status") == "found":
                # Test D: Inspect desktop/screen properties
                test_window_desktop_property(runner, args.window_id)

                # Test E: Mutations (only with --mutate)
                if args.mutate:
                    test_mutations(runner, args.window_id, desktops)
                else:
                    print()
                    info("Skipping Test E (mutation) — pass --mutate to enable")
        else:
            print()
            warn("Tests C/D/E skipped — no --id provided.")
            info("Run kwin_window_probe.py to get an internalId, then:")
            info('  python3 kwin_mutation_test.py --id "{uuid}"')

    finally:
        loop.quit()
        try:
            registration.unpublish()
        except Exception:
            pass

    head("═══ Done ════════════════════════════════════════════════════════")


if __name__ == "__main__":
    main()
